def get_bank(kelas):
    """Mengembalikan bank soal sesuai kelas (K3 atau K4)."""
    return UAS_BANK_K3 if str(kelas).strip().upper() == "K3" else UAS_BANK_K4


assert len(UAS_BANK_K3) == 200 and len(UAS_BANK_K4) == 200, "Tiap kelas harus 200 soal"
# Pastikan K3 dan K4 tidak beririsan (soal berbeda antar kelas)
_q3 = {q["q"] for q in UAS_BANK_K3}
_q4 = {q["q"] for q in UAS_BANK_K4}
assert _q3.isdisjoint(_q4), "Soal K3 dan K4 tidak boleh sama"
